671: 					}
672: 
673: 					/* __GDPR__
674: 						"serviceExited" : {
675: 							"owner": "mjbvz",
676: 							"${include}": [
677: 								"${TypeScriptCommonProperties}"
678: 							]
679: 						}
680: 					*/
681: 					this.logTelemetry('serviceExited');
